-- ---------------------------------------------------------- -- Tabel structuur voor tabel ccggtabel-- -- --------------------------------------------------------DROP TABLE IF EXISTS ccggtabel;CREATE TABLE ccggtabel ( ccgg_id smallint(11) NOT NULL auto_increment, persoon_id smallint(11) NOT NULL default '0', ccgg varchar(10) default NULL, ccgg_categorie varchar(30) default NULL, ccgg_text varchar(160) default NULL, ccgg_gewicht smallint(4) default NULL,PRIMARY KEY (ccgg_id), KEY persoon_id (persoon_id), KEY ccgg (ccgg)) TYPE=MyISAM AUTO_INCREMENT=1000 ;-- contekst-- cues-- gevoel-- gedachte-- 
